  "cases": [
    {
      "input": {
        "op": "from",
        "items": [
          "meat",
          "cheese",
          "beer",
          "bread"
        ],
        "value": "beer"
      },
      "expected_output": "length=2\nitems=beer,bread\n"
    },
    {
      "input": {
        "op": "from",
        "items": [
          "meat",
          "cheese",
          "beer",
          "bread"
        ],
        "value": "meat"
      },
      "expected_output": "length=4\nitems=meat,cheese,beer,bread\n"
    },
    {
      "input": {
        "op": "from",
        "items": [
          1,
          2,
          3,
          4,
          5,
          6
        ],
        "value": 7
      },
      "expected_output": "length=0\nitems=\n"
    }
  ]
}

