Here are the public test cases for feature5_stable_priority_queue:
{
  "description": "A priority queue keyed on string length (shorter strings dequeue first) that preserves insertion order among equal-length strings (stability). Dequeuing drains the whole queue in priority-then-arrival order; a consistency flag confirms the internal heap invariant holds.",
  "cases": [
    {
      "input": {
        "op": "priority_queue",
        "items": [
          "ccc",
          "a",
          "dd",
          "b",
          "eee",
          "cc"
        ]
      },
      "expected_output": "dequeued=a,b,dd,cc,ccc,eee\nconsistent=true\n"
    },
    {
      "input": {
        "op": "priority_queue",
        "items": [
          "bb",
          "aa",
          "c",
          "dddd",
          "e"
        ]
      },
      "expected_output": "dequeued=c,e,bb,aa,dddd\nconsistent=true\n"
    }
  ]
}

Here are the public test cases for feature6_atomic_switch:
{
  "description": "A two-state (on/off) latch. Transition operations return true only when they actually changed the state and false when it was already in the target state. State queries report the current position. Conditional runners execute an action only in the matching state, returning whether they ran. If an action throws during a transition, the latch reverts to its prior state and surfaces the failure.",
  "cases": [
    {
      "input": {
        "op": "switch",
        "start": false,
        "commands": [
          "is_off",
          "is_on",
          "switch_on",
          "is_on",
          "switch_on",
          "switch_off",
          "is_off",
          "switch_off"
        ]
      },
      "expected_output": "is_off -> true\nis_on -> false\nswitch_on -> true\nis_on -> true\nswitch_on -> false\nswitch_off -> true\nis_off -> true\nswitch_off -> false\n"
    },
    {
      "input": {
        "op": "switch",
        "start": true,
        "commands": [
          "is_on",
          "is_off"
        ]
      },
      "expected_output": "is_on -> true\nis_off -> false\n"
    },
    {
      "input": {
        "op": "switch",
        "start": false,
        "commands": [
          "switch_on_throw",
          "is_off",
          "is_on"
        ]
      },
      "expected_output": "switch_on_throw -> error=action_failed\nis_off -> true\nis_on -> false\n"
    },
    {
      "input": {
        "op": "switch",
        "start": true,
        "commands": [
          "switch_off_throw",
          "is_on",
          "is_off"
        ]
      },
      "expected_output": "switch_off_throw -> error=action_failed\nis_on -> true\nis_off -> false\n"
    }
  ]
}

Here are the public test cases for feature7_token_bucket:
{
  "description": "A rate limiter. The bucket holds up to capacity tokens and gains one token every rate ticks of a caller-supplied clock. Each offer of a cost returns how many ticks the caller must wait before that cost can be paid (0 if payable immediately). The bucket starts full, caps at capacity, supports costs larger than capacity, a cost of zero, zero capacity, and clocks that start negative or run very slowly. Invalid construction (negative capacity, non-positive rate) and a negative cost are rejected as normalized errors.",
  "cases": [
    {
      "input": {
        "op": "token_bucket",
        "capacity": 10,
        "rate": 1,
        "steps": [
          {
            "offer": 1
          },
          {
            "offer": 1
          },
          {
            "offer": 1
          },
          {
            "offer": 7
          },
          {
            "offer": 3
          }
        ]
      },
      "expected_output": "offer cost=1 delay=0\noffer cost=1 delay=0\noffer cost=1 delay=0\noffer cost=7 delay=0\noffer cost=3 delay=3\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": 10,
        "rate": 2,
        "steps": [
          {
            "offer": 5
          },
          {
            "offer": 20
          },
          {
            "set_time": 30,
            "offer": 1
          },
          {
            "set_time": 34,
            "offer": 1
          },
          {
            "offer": 1
          }
        ]
      },
      "expected_output": "offer cost=5 delay=0\noffer cost=20 delay=30\noffer cost=1 delay=2\noffer cost=1 delay=0\noffer cost=1 delay=2\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": 0,
        "rate": 2,
        "steps": [
          {
            "offer": 10
          },
          {
            "set_time": 40,
            "offer": 10
          }
        ]
      },
      "expected_output": "offer cost=10 delay=20\noffer cost=10 delay=20\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": 10,
        "rate": 1,
        "steps": [
          {
            "offer": 10
          },
          {
            "set_time": 100000,
            "offer": 20
          }
        ]
      },
      "expected_output": "offer cost=10 delay=0\noffer cost=20 delay=10\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": -1,
        "rate": 1,
        "steps": []
      },
      "expected_output": "error=negative_capacity\nparam=capacity\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": 10,
        "rate": 0,
        "steps": []
      },
      "expected_output": "error=nonpositive_rate\nparam=rate\n"
    },
    {
      "input": {
        "op": "token_bucket",
        "capacity": 10,
        "rate": 1,
        "steps": [
          {
            "offer": -1
          }
        ]
      },
      "expected_output": "error=negative_cost\nparam=cost\n"
    }
  ]
}

Here are the public test cases for feature8_1_bytes_concat_indexof:
{
  "description": "Concatenating two byte sequences yields a sequence whose length is the sum of the parts; locating a byte returns its zero-based position in the concatenation, or -1 when the byte is absent.",
  "cases": [
    {
      "input": {
        "op": "bytes_concat",
        "a": [
          1
        ],
        "b": [
          2
        ],
        "index_of": [
          2,
          3
        ]
      },
      "expected_output": "count=2\nindex_of 2 -> 1\nindex_of 3 -> -1\n"
    },
    {
      "input": {
        "op": "bytes_concat",
        "a": [
          10,
          20,
          30
        ],
        "b": [
          40,
          50
        ],
        "index_of": [
          10,
          50,
          99
        ]
      },
      "expected_output": "count=5\nindex_of 10 -> 0\nindex_of 50 -> 4\nindex_of 99 -> -1\n"
    }
  ]
}

