Here are the public test cases for feature9_1_split_dotted_path:
{
  "description": "Split a dot-delimited path into segments, but treat any double-quoted span as a single literal segment so that dots inside quotes are preserved rather than used as separators.",
  "cases": [
    {
      "input": {
        "op": "split_path",
        "path": "config.server.host.port"
      },
      "expected_output": "count=4\nsegment=config\nsegment=server\nsegment=host\nsegment=port\n"
    },
    {
      "input": {
        "op": "split_path",
        "path": "system.deployment.\"/a/dotted.path/*\".handler"
