      "expected_output": "count=4\nsegment=system\nsegment=deployment\nsegment=/a/dotted.path/*\nsegment=handler\n"
    },
    {
      "input": {
        "op": "split_path",
        "path": "\"ab.cd\""
      },
      "expected_output": "count=1\nsegment=ab.cd\n"
    }
  ]
}

